import stylex from '@universe-design/stylex';
import { cssFontMedium } from './typography-font-weight-medium.css';

const chromeMinFontSize = 12;
const fontSize = 10;
const lineHeight = 16;

export const cssTypographyCaption1 = stylex.compose(
  stylex.create({
    fontSize,
    lineHeight: `${lineHeight}px`,
  }),
  cssFontMedium,
);
cssTypographyCaption1.alias = 'ud-typography-caption-1';

export const cssTypographyCaption1Hack = stylex.compose(
  stylex.create({
    fontSize: chromeMinFontSize,
    lineHeight: `${(lineHeight / fontSize) * chromeMinFontSize}px`,
    zoom: fontSize / chromeMinFontSize,
    '-webkit-text-size-adjust': 'none',
  }),
  cssFontMedium,
);
cssTypographyCaption1Hack.alias = 'ud-typography-caption-1';
